const event = $input.first().json.body;

if (event.type !== 'checkout.session.completed') {
  return [{json: {status: 'ignored', reason: 'checkout not complete'}}];
}

const session = event.data.object;
const metadata = session.metadata || {};

return [{
  json: {
    customer_email: session.customer_email || session.customer_details?.email,
    customer_name: session.customer_details?.name || 'Unknown',
    stripe_subscription_id: session.subscription,
    stripe_customer_id: session.customer,
    tier: metadata.tier || 'business',
    deployment_type: metadata.deployment || 'private',
    amount_paid: session.amount_total
  }
}];

const clientId = $input.first().json[0]?.id || 1;
const data = $input.first().json;

return [{
  json: {
    task_type: 'DEPLOY',
    payload: {
      goal: 'Provision SAOS Business Fleet for new client',
      client_id: clientId,
      customer_email: data.customer_email,
      customer_name: data.customer_name,
      tier: data.tier,
      deployment_type: data.deployment_type
    }
  }
}];

const taskId = $input.first().json[0]?.id;
return [{
  json: {
    status: 'success',
    message: 'Client provisioned queued',
    task_id: taskId
  }
}];
